function sumPrimes(arr) {
  // Function to check if a number is prime
  function isPrime(num) {
    for (let i = 2; i < num; i++) {
      if (num % i === 0) {
        return false;
      }
    }
    return num > 1;
  }

  let sum = 0;
  for (let i = 0; i < arr.length; i++) {
    // Exclude the number 3 and check if the number is prime
    if (arr[i] !== 3 && isPrime(arr[i])) {
      sum += arr[i];
    }
  }
  return sum;
}

