  const spectralType = object.spectralProperties[0];

  if (spectralType.startsWith("M")) {
    if (object.hasAtmosphere) {
      if (object.isExoplanetHost) {
        return "M-type star, possible planet host with atmosphere";
      } else {
        return "M-type star with atmosphere";
      }
    } else {
      return "M-type star without atmosphere";
    }
  } else {
    return "Other type of star";
  }
}

const object = {
  name: "Proxima Centauri",
  spectralProperties: ["M5.5Ve"],
  hasAtmosphere: true,
  isExoplanetHost: false
};

const classification = classifyCelestialObject(object);
console.log(classification);
```

